INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4519ef74-d15b-4c31-b9a6-4af93033193a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flutter and React Native Architecture: A Comparative Look$escape$,
  $escape$Flutter's architecture is based on the Skia graphics engine and Dart runtime. Unlike React Native, Flutter doesn't rely on JavaScript or a bridge layer. However, Flutter does provide a way to call native code through the Platform channel. On the other hand, React Native's new architecture is based on Fabric, which provides a more efficient way to interact with native code. Turbo Modules, introduced in React Native 0.68, further optimize the performance by compiling JavaScript to native code. Flutter, however, does not require such optimizations due to its native Dart runtime. JSI (JavaScript Interface) is used in React Native to interact with native code, while Flutter uses the Platform channel for the same purpose.$escape$,
  NULL,
  NULL,
